import{_ as a,c as e,o as l,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"技能管理: 查询可用技能 | opencode-agent-skills","description":"学习 get_available_skills 工具的使用方法。通过搜索、命名空间和过滤快速定位技能，掌握技能发现和管理的核心功能。","frontmatter":{"title":"技能管理: 查询可用技能 | opencode-agent-skills","sidebarTitle":"快速找技能","subtitle":"技能管理: 查询可用技能","description":"学习 get_available_skills 工具的使用方法。通过搜索、命名空间和过滤快速定位技能，掌握技能发现和管理的核心功能。","tags":["技能管理","工具使用","命名空间"],"prerequisite":["start-installation"],"order":2},"headers":[],"relativePath":"zh/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md","filePath":"zh/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"}'),i={name:"zh/joshuadavidthomas/opencode-agent-skills/platforms/listing-available-skills/index.md"};function t(p,s,o,c,d,r){return l(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="查询和列出可用技能" tabindex="-1">查询和列出可用技能 <a class="header-anchor" href="#查询和列出可用技能" aria-label="Permalink to &quot;查询和列出可用技能&quot;">​</a></h1><h2 id="学完你能做什么" tabindex="-1">学完你能做什么 <a class="header-anchor" href="#学完你能做什么" aria-label="Permalink to &quot;学完你能做什么&quot;">​</a></h2><ul><li>使用 <code>get_available_skills</code> 工具列出所有可用技能</li><li>通过搜索查询过滤特定技能</li><li>使用命名空间（如 <code>project:skill-name</code>）精确定位技能</li><li>识别技能来源和可执行脚本列表</li></ul><h2 id="你现在的困境" tabindex="-1">你现在的困境 <a class="header-anchor" href="#你现在的困境" aria-label="Permalink to &quot;你现在的困境&quot;">​</a></h2><p>你想使用某个技能，但记不清它的确切名称。也许你知道它是项目里的某个技能，但不知道在哪个发现路径下。或者你只是想快速浏览一下当前项目有哪些技能可用。</p><h2 id="什么时候用这一招" tabindex="-1">什么时候用这一招 <a class="header-anchor" href="#什么时候用这一招" aria-label="Permalink to &quot;什么时候用这一招&quot;">​</a></h2><ul><li><strong>探索新项目</strong>：加入一个新项目时，快速了解有哪些可用的技能</li><li><strong>技能名称不确定</strong>：只记得技能的部分名称或描述，需要模糊匹配</li><li><strong>多命名空间冲突</strong>：项目级和用户级有同名技能，需要明确指定使用哪个</li><li><strong>查找脚本</strong>：想知道技能目录下有哪些可执行的自动化脚本</li></ul><h2 id="核心思路" tabindex="-1">核心思路 <a class="header-anchor" href="#核心思路" aria-label="Permalink to &quot;核心思路&quot;">​</a></h2><p><code>get_available_skills</code> 工具帮你查看当前会话可用的所有技能。插件会自动从 6 个发现路径扫描技能：</p><div class="info custom-block"><p class="custom-block-title">技能发现优先级</p><ol><li><code>.opencode/skills/</code> (项目级 OpenCode)</li><li><code>.claude/skills/</code> (项目级 Claude)</li><li><code>~/.config/opencode/skills/</code> (用户级 OpenCode)</li><li><code>~/.claude/skills/</code> (用户级 Claude)</li><li><code>~/.claude/plugins/cache/</code> (插件缓存)</li><li><code>~/.claude/plugins/marketplaces/</code> (已安装插件)</li></ol></div><p>同名技能按优先级只保留第一个，后续的被忽略。</p><p>工具返回的信息包括：</p><ul><li><strong>技能名称</strong></li><li><strong>来源标签</strong>（project、user、claude-project 等）</li><li><strong>描述</strong></li><li><strong>可执行脚本列表</strong>（如果有）</li></ul><div class="tip custom-block"><p class="custom-block-title">命名空间语法</p><p>你可以用 <code>namespace:skill-name</code> 格式明确指定来源：</p><ul><li><code>project:my-skill</code> - 使用项目级 OpenCode 技能（<code>.opencode/skills/</code>）</li><li><code>claude-project:my-skill</code> - 使用项目级 Claude 技能（<code>.claude/skills/</code>）</li><li><code>user:my-skill</code> - 使用用户级 OpenCode 技能（<code>~/.config/opencode/skills/</code>）</li><li><code>claude-user:my-skill</code> - 使用用户级 Claude 技能（<code>~/.claude/skills/</code>）</li><li><code>claude-plugins:my-skill</code> - 使用 Claude 插件中的技能</li></ul></div><h2 id="跟我做" tabindex="-1">跟我做 <a class="header-anchor" href="#跟我做" aria-label="Permalink to &quot;跟我做&quot;">​</a></h2><h3 id="第-1-步-列出所有可用技能" tabindex="-1">第 1 步：列出所有可用技能 <a class="header-anchor" href="#第-1-步-列出所有可用技能" aria-label="Permalink to &quot;第 1 步：列出所有可用技能&quot;">​</a></h3><p>在 OpenCode 中直接让 AI 列出技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>列出所有可用的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>skill-helper (project)</span></span>
<span class="line"><span>  Git 操作和分支管理助手 [scripts: tools/branch.sh, tools/commit.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  单元测试和覆盖率分析工具</span></span>
<span class="line"><span></span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span>
<span class="line"><span></span></span>
<span class="line"><span>claude-code-superpowers (claude-plugins)</span></span>
<span class="line"><span>  完整的软件开发工作流</span></span></code></pre></div><p><strong>你应该看到</strong>：一个技能列表，每个技能显示名称、来源标签、描述和脚本列表。</p><h3 id="第-2-步-使用搜索查询过滤" tabindex="-1">第 2 步：使用搜索查询过滤 <a class="header-anchor" href="#第-2-步-使用搜索查询过滤" aria-label="Permalink to &quot;第 2 步：使用搜索查询过滤&quot;">​</a></h3><p>如果你只记得技能的部分名称：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>查找包含 &quot;docker&quot; 的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>搜索会匹配技能名称和描述中的关键词，支持 <code>*</code> 通配符：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>查找以 &quot;test&quot; 开头的技能</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>test-helper (user)</span></span>
<span class="line"><span>  单元测试和覆盖率分析工具</span></span></code></pre></div><p><strong>你应该看到</strong>：只显示匹配查询条件的技能。</p><h3 id="第-3-步-体验模糊匹配建议" tabindex="-1">第 3 步：体验模糊匹配建议 <a class="header-anchor" href="#第-3-步-体验模糊匹配建议" aria-label="Permalink to &quot;第 3 步：体验模糊匹配建议&quot;">​</a></h3><p>如果你输入了错误的技能名称：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>我想用 docker-asistant</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>No skills found matching &quot;docker-asistant&quot;. Did you mean &quot;docker-helper&quot;?</span></span></code></pre></div><p>插件会基于 Levenshtein 距离计算相似度，自动建议最接近的技能名称。</p><p><strong>你应该看到</strong>：错误提示和正确的技能建议。</p><h3 id="第-4-步-使用命名空间精确定位" tabindex="-1">第 4 步：使用命名空间精确定位 <a class="header-anchor" href="#第-4-步-使用命名空间精确定位" aria-label="Permalink to &quot;第 4 步：使用命名空间精确定位&quot;">​</a></h3><p>假设项目级和用户级都有名为 <code>build-helper</code> 的技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>列出 build-helper 的详细信息</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>build-helper (project)</span></span>
<span class="line"><span>  项目特定的构建配置和编译优化 [scripts: build.sh, optimize.sh]</span></span></code></pre></div><p>如果用户想要用户级的技能：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>使用 user:build-helper</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>build-helper (user)</span></span>
<span class="line"><span>  通用构建工具链和持续集成配置 [scripts: ci.sh, test.sh]</span></span></code></pre></div><p><strong>你应该看到</strong>：通过命名空间前缀可以访问不同来源的同名技能。</p><h3 id="第-5-步-检查可执行脚本" tabindex="-1">第 5 步：检查可执行脚本 <a class="header-anchor" href="#第-5-步-检查可执行脚本" aria-label="Permalink to &quot;第 5 步：检查可执行脚本&quot;">​</a></h3><p>查看技能目录下有哪些脚本：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户输入：</span></span>
<span class="line"><span>docker-helper 有哪些脚本？</span></span>
<span class="line"><span></span></span>
<span class="line"><span>系统回复：</span></span>
<span class="line"><span>docker-helper (project)</span></span>
<span class="line"><span>  Docker 容器化和部署指南 [scripts: build.sh, deploy.sh]</span></span></code></pre></div><p>脚本会显示在技能信息的方括号中，用逗号分隔。你可以用 <code>run_skill_script</code> 工具执行这些脚本。</p><p><strong>你应该看到</strong>：技能名称后面跟着 <code>[scripts: 脚本路径1, 脚本路径2, ...]</code> 格式的列表。</p><h2 id="检查点-✅" tabindex="-1">检查点 ✅ <a class="header-anchor" href="#检查点-✅" aria-label="Permalink to &quot;检查点 ✅&quot;">​</a></h2><ul><li>[ ] 你能列出所有可用的技能吗？</li><li>[ ] 你能用搜索查询过滤特定技能吗？</li><li>[ ] 你能理解技能来源标签的含义吗（project、user、claude-project 等）？</li><li>[ ] 你能说出技能命名空间的作用和语法吗？</li><li>[ ] 你能从技能信息中识别可执行脚本列表吗？</li></ul><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><h3 id="陷阱-1-同名技能的覆盖" tabindex="-1">陷阱 1：同名技能的覆盖 <a class="header-anchor" href="#陷阱-1-同名技能的覆盖" aria-label="Permalink to &quot;陷阱 1：同名技能的覆盖&quot;">​</a></h3><p>如果项目级和用户级有同名技能，你可能会困惑为什么加载的不是你期望的技能。</p><p><strong>原因</strong>：技能按优先级发现，项目级优先于用户级，同名只保留第一个。</p><p><strong>解决</strong>：使用命名空间明确指定，如 <code>user:my-skill</code> 而不是 <code>my-skill</code>。</p><h3 id="陷阱-2-搜索大小写敏感" tabindex="-1">陷阱 2：搜索大小写敏感 <a class="header-anchor" href="#陷阱-2-搜索大小写敏感" aria-label="Permalink to &quot;陷阱 2：搜索大小写敏感&quot;">​</a></h3><p>搜索查询使用正则表达式，但设置了 <code>i</code> 标志，所以是不区分大小写的。</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 这些搜索是等效的</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;DOCKER&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;Docker&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><h3 id="陷阱-3-通配符的转义" tabindex="-1">陷阱 3：通配符的转义 <a class="header-anchor" href="#陷阱-3-通配符的转义" aria-label="Permalink to &quot;陷阱 3：通配符的转义&quot;">​</a></h3><p>搜索中的 <code>*</code> 会被自动转换为 <code>.*</code> 正则表达式，不需要手动转义：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 搜索以 &quot;test&quot; 开头的技能</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">get_available_skills(query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">&quot;test*&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 等同于正则表达式 /test.*/i</span></span></code></pre></div><h2 id="本课小结" tabindex="-1">本课小结 <a class="header-anchor" href="#本课小结" aria-label="Permalink to &quot;本课小结&quot;">​</a></h2><p><code>get_available_skills</code> 是探索技能生态的工具，支持：</p><ul><li><strong>列出所有技能</strong>：不加参数调用</li><li><strong>搜索过滤</strong>：通过 <code>query</code> 参数匹配名称和描述</li><li><strong>命名空间</strong>：用 <code>namespace:skill-name</code> 精确定位</li><li><strong>模糊匹配建议</strong>：拼写错误时自动提示正确名称</li><li><strong>脚本列表</strong>：显示可执行的自动化脚本</li></ul><p>插件会在会话开始时自动注入技能列表，所以你通常不需要手动调用这个工具。但在以下场景下它很有用：</p><ul><li>想快速浏览可用技能</li><li>记不清技能的确切名称</li><li>需要区分同名技能的不同来源</li><li>想查看某个技能的脚本列表</li></ul><h2 id="下一课预告" tabindex="-1">下一课预告 <a class="header-anchor" href="#下一课预告" aria-label="Permalink to &quot;下一课预告&quot;">​</a></h2><blockquote><p>下一课我们学习 <strong><a href="./../loading-skills-into-context/">加载技能到会话上下文</a></strong>。</p><p>你会学到：</p><ul><li>使用 use_skill 工具加载技能到当前会话</li><li>理解技能内容如何以 XML 格式注入到上下文</li><li>掌握 Synthetic Message Injection 机制（synthetic 消息注入）</li><li>了解技能在会话压缩后如何保持可用</li></ul></blockquote><hr><h2 id="附录-源码参考" tabindex="-1">附录：源码参考 <a class="header-anchor" href="#附录-源码参考" aria-label="Permalink to &quot;附录：源码参考&quot;">​</a></h2><details><summary><strong>点击展开查看源码位置</strong></summary><blockquote><p>更新时间：2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>功能</th><th>文件路径</th><th>行号</th></tr></thead><tbody><tr><td>GetAvailableSkills 工具定义</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/tools.ts#L29-L72" target="_blank" rel="noreferrer"><code>src/tools.ts</code></a></td><td>29-72</td></tr><tr><td>discoverAllSkills 函数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L240-L263" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>240-263</td></tr><tr><td>resolveSkill 函数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L269-L283" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>269-283</td></tr><tr><td>findClosestMatch 函数</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L88-L125" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>88-125</td></tr></tbody></table><p><strong>关键类型</strong>：</p><ul><li><code>SkillLabel = &quot;project&quot; | &quot;user&quot; | &quot;claude-project&quot; | &quot;claude-user&quot; | &quot;claude-plugins&quot;</code>：技能来源标签枚举</li></ul><p><strong>关键常量</strong>：</p><ul><li>模糊匹配阈值：<code>0.4</code>（<code>utils.ts:124</code>）- 相似度低于此值不返回建议</li></ul><p><strong>关键函数</strong>：</p><ul><li><code>GetAvailableSkills()</code>：返回格式化的技能列表，支持查询过滤和模糊匹配建议</li><li><code>resolveSkill(skillName: string, skillsByName: Map&lt;string, Skill&gt;)</code>：支持 <code>namespace:skill-name</code> 格式的技能解析</li><li><code>findClosestMatch(input: string, candidates: string[])</code>：基于多种匹配策略（前缀、包含、编辑距离）计算最佳匹配</li></ul><p><strong>业务规则</strong>：</p><ul><li>同名技能按发现顺序去重，仅保留第一个（<code>skills.ts:258</code>）</li><li>搜索查询支持通配符 <code>*</code>，自动转换为正则表达式（<code>tools.ts:43</code>）</li><li>模糊匹配建议只在有查询参数且无结果时触发（<code>tools.ts:49-57</code>）</li></ul></details>`,64)])])}const k=a(i,[["render",t]]);export{u as __pageData,k as default};
